// // This module implements a 16-bit register that loads new data on every negative edge of the clock signal clk when the enable signal is deasserted.
module data_register(
    input clk,
    input rst,
    input en,
    input [15:0] d,

    output reg [15:0] q
);
    always @(posedge clk) begin
        if (rst) begin
            q <= 16'b0000000000000000;
        end else if (en) begin
            q <= d;
        end
    end
endmodule
